function cl_fix_resize (a			: std_logic_vector; 
						a_fmt		: FixFormat_t; 
						result_fmt	: FixFormat_t; 
						round		: FixRound_t	:= Trunc_s; 
						saturate	: FixSaturate_t	:= Warn_s) 
